_L_z06_CopyBlock_Loop:
    move.b  ($00,A4),D1   ; ptr lo
    move.b  ($01,A4),D4  ; ptr hi
    lsl.w   #8,D4
    or.w    D1,D4             ; D4 = NES ptr addr
    ext.l   D4
    add.l   #NES_RAM,D4       ; → Genesis addr
    movea.l D4,A0
    move.b  (A0,D3.W),D0     ; LDA ($nn),Y
    move.b  ($02,A4),D1   ; ptr lo
    move.b  ($03,A4),D4  ; ptr hi
    lsl.w   #8,D4
    or.w    D1,D4
    ext.l   D4
    add.l   #NES_RAM,D4
    movea.l D4,A0
    move.b  D0,(A0,D3.W)     ; STA ($nn),Y
    move.b  ($0002,A4),D0
    move.b  ($0004,A4),D1
    cmp.b   D1,D0
    bne  _L_z06_CopyBlock_Next
    move.b  ($0003,A4),D0
    move.b  ($0005,A4),D1
    cmp.b   D1,D0
    bne  _L_z06_CopyBlock_Next
    addq.b  #1,($0013,A4)
    rts

