    andi.b  #$EE,CCR  ; CLC: clear C+X
    move.b  #$01,D1
    addx.b  D1,D0   ; ADC #$01 (X flag = 6502 C)
    move.b  D0,($0002,A4)
    move.b  ($0003,A4),D0
    move.b  #$00,D1
    addx.b  D1,D0   ; ADC #$00 (X flag = 6502 C)
    move.b  D0,($0003,A4)
    move.b  ($0000,A4),D0
    andi.b  #$EE,CCR  ; CLC: clear C+X
    move.b  #$01,D1
